// dpe_stub_nldpe.v -- behavioral DPE model
// Generated by nl_dpe/gen_dpe_stub.py from per-arch JSON config.
// Architecture        : nldpe (NL-DPE)
// KERNEL_WIDTH (rows) : 256
// NUM_COLS            : 256
// DPE_BUF_WIDTH       : 40  (elems/strobe = 5)
// PRECISION_BITS      : 8
// PIPELINE_DEPTH      : 3  (fire -> VMM -> accumulate)
// COMPUTE_CYCLES      : 10  (= PRECISION_BITS + PIPELINE_DEPTH - 1)
// LOAD_STROBES        : 52
// OUTPUT_CYCLES       : 52
// T_fill              : 114
// T_steady (max LCO)  : 52
// ACAM branch present : True
//
// FSM:  S_IDLE -> S_LOAD -> S_WAIT_EXEC -> S_COMPUTE -> S_OUTPUT -> S_DRAIN
// Behavioral single-clock VMM at S_WAIT_EXEC fire-time.
// Weights are loaded by the TB through hierarchical force:
//     dut.weights[r][c] = <int8>;   (no weight_wen port).

module dpe_stub_nldpe #(
    parameter KERNEL_WIDTH   = 256,
    parameter NUM_COLS       = 256,
    parameter DPE_BUF_WIDTH  = 40,
    parameter PRECISION_BITS = 8,
    parameter PIPELINE_DEPTH = 3,
    parameter ACAM_MODE      = 0  // 0=ADC/VMM (no NL), 1=exp(approx 1+x+x^2/2), 2=log(approx x-1)
)(
    input  wire                       clk,
    input  wire                       reset,
    input  wire [DPE_BUF_WIDTH-1:0]   data_in,
    input  wire [1:0]                 nl_dpe_control,
    input  wire                       shift_add_control,
    input  wire                       w_buf_en,
    input  wire                       shift_add_bypass,
    input  wire                       load_output_reg,
    input  wire                       load_input_reg,
    output reg                        MSB_SA_Ready,
    output reg  [DPE_BUF_WIDTH-1:0]   data_out,
    output reg                        dpe_done,
    output reg                        reg_full,
    output reg                        shift_add_done,
    output reg                        shift_add_bypass_ctrl
);

    // Tie-off auxiliary handshake inputs (kept in port list for
    // protocol compatibility with the legacy controller).
    wire _unused_aux = shift_add_control | shift_add_bypass |
                       load_output_reg   | load_input_reg;

    // Derived per-pass cycle counters
    localparam ELEMS_PER_STROBE = DPE_BUF_WIDTH / 8;
    localparam LOAD_STROBES  = (KERNEL_WIDTH + ELEMS_PER_STROBE - 1) / ELEMS_PER_STROBE;
    localparam OUTPUT_CYCLES = (NUM_COLS    + ELEMS_PER_STROBE - 1) / ELEMS_PER_STROBE;
    // Precision-driven bit-serial compute pipeline:
    // fire -> VMM -> accumulate; total cycles = PRECISION + DEPTH - 1.
    localparam COMPUTE_CYCLES = PRECISION_BITS + PIPELINE_DEPTH - 1;

    // Weight memory (hierarchical-force loaded from TB)
    reg signed [7:0] weights [0:KERNEL_WIDTH-1][0:NUM_COLS-1];

    // Input buffer (one int8 per row)
    reg signed [7:0] input_buffer [0:KERNEL_WIDTH-1];
    reg [15:0] load_count;
    reg [15:0] strobe_count;

    // VMM accumulators (full int32 per output column)
    reg signed [31:0] vmm_result [0:NUM_COLS-1];
    reg [15:0] output_col_idx;
    reg [15:0] compute_cycle_cnt;

    // Initialise weight memory to zero (sim-only)
    integer wi, wj;
    initial begin
        for (wi = 0; wi < KERNEL_WIDTH; wi = wi + 1)
            for (wj = 0; wj < NUM_COLS; wj = wj + 1)
                weights[wi][wj] = 0;
    end

    // FSM state encoding
    localparam S_IDLE      = 3'd0;
    localparam S_LOAD      = 3'd1;
    localparam S_WAIT_EXEC = 3'd2;
    localparam S_COMPUTE   = 3'd3;
    localparam S_OUTPUT    = 3'd4;
    localparam S_DRAIN     = 3'd5;
    reg [2:0] state;

    integer r, c, b;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            state <= S_IDLE;
            load_count <= 0;
            strobe_count <= 0;
            data_out <= 0;
            dpe_done <= 0;
            reg_full <= 0;
            MSB_SA_Ready <= 1;
            shift_add_done <= 1;
            shift_add_bypass_ctrl <= 1;
            compute_cycle_cnt <= 0;
            output_col_idx <= 0;
        end else begin
            dpe_done <= 0;  // default low (one-shot in S_OUTPUT)
            case (state)
                S_IDLE: begin
                    reg_full <= 0;
                    MSB_SA_Ready <= 1;
                    shift_add_done <= 1;
                    load_count <= 0;
                    strobe_count <= 0;
                    compute_cycle_cnt <= 0;
                    output_col_idx <= 0;
                    if (w_buf_en) begin
                        for (b = 0; b < ELEMS_PER_STROBE; b = b + 1)
                            if (b < KERNEL_WIDTH)
                                input_buffer[b] <= data_in[b*8 +: 8];
                        load_count <= (ELEMS_PER_STROBE < KERNEL_WIDTH) ?
                                       ELEMS_PER_STROBE : KERNEL_WIDTH;
                        strobe_count <= 1;
                        if (1 >= LOAD_STROBES) begin
                            reg_full <= 1;
                            MSB_SA_Ready <= 0;
                            shift_add_done <= 0;
                            state <= S_WAIT_EXEC;
                        end else begin
                            state <= S_LOAD;
                        end
                    end
                end
                S_LOAD: begin
                    if (w_buf_en) begin
                        if (strobe_count + 1 >= LOAD_STROBES) begin
                            // Last LOAD strobe — write input_buffer with
                            // BLOCKING assignment so the VMM below reads the
                            // freshly-loaded final bytes (mixing blocking +
                            // non-blocking is sim-only behavioural; there is
                            // no synthesised hardware here). Then fire VMM
                            // combinationally so T_fill = L + C + O matches §4.
                            for (b = 0; b < ELEMS_PER_STROBE; b = b + 1)
                                if (load_count + b < KERNEL_WIDTH)
                                    input_buffer[load_count + b] = data_in[b*8 +: 8];
                            load_count <= load_count + ELEMS_PER_STROBE;
                            strobe_count <= strobe_count + 1;
                            reg_full <= 1;
                            MSB_SA_Ready <= 0;
                            shift_add_done <= 0;
                            if (nl_dpe_control == 2'b11) begin
                                for (c = 0; c < NUM_COLS; c = c + 1) begin
                                    vmm_result[c] = 0;
                                    for (r = 0; r < KERNEL_WIDTH; r = r + 1) begin
                                        vmm_result[c] = vmm_result[c] +
                                            input_buffer[r] * weights[r][c];
                                    end
                                end
                                if (ACAM_MODE == 1) begin
                                    for (c = 0; c < NUM_COLS; c = c + 1)
                                        vmm_result[c] = 1 + vmm_result[c] +
                                            (vmm_result[c] * vmm_result[c]) / 2;
                                end else if (ACAM_MODE == 2) begin
                                    for (c = 0; c < NUM_COLS; c = c + 1)
                                        vmm_result[c] = vmm_result[c] - 1;
                                end
                                compute_cycle_cnt <= 0;
                                output_col_idx <= 0;
                                state <= S_COMPUTE;
                            end else begin
                                state <= S_WAIT_EXEC;
                            end
                        end else begin
                            // Non-final LOAD strobe — keep NBA semantics.
                            for (b = 0; b < ELEMS_PER_STROBE; b = b + 1)
                                if (load_count + b < KERNEL_WIDTH)
                                    input_buffer[load_count + b] <= data_in[b*8 +: 8];
                            load_count <= load_count + ELEMS_PER_STROBE;
                            strobe_count <= strobe_count + 1;
                        end
                    end
                end
                S_WAIT_EXEC: begin
                    if (nl_dpe_control == 2'b11) begin
                        // Single-clock behavioral VMM:
                        // vmm_result[c] = sum_r input_buffer[r] * weights[r][c]
                        for (c = 0; c < NUM_COLS; c = c + 1) begin
                            vmm_result[c] = 0;
                            for (r = 0; r < KERNEL_WIDTH; r = r + 1) begin
                                vmm_result[c] = vmm_result[c] +
                                    input_buffer[r] * weights[r][c];
                            end
                        end
                        // ACAM_MODE: 0=ADC, 1=exp approx, 2=log approx
                        if (ACAM_MODE == 1) begin
                            for (c = 0; c < NUM_COLS; c = c + 1)
                                vmm_result[c] = 1 + vmm_result[c] +
                                    (vmm_result[c] * vmm_result[c]) / 2;
                        end else if (ACAM_MODE == 2) begin
                            for (c = 0; c < NUM_COLS; c = c + 1)
                                vmm_result[c] = vmm_result[c] - 1;
                        end
                        compute_cycle_cnt <= 0;
                        output_col_idx <= 0;
                        state <= S_COMPUTE;
                    end
                end
                S_COMPUTE: begin
                    compute_cycle_cnt <= compute_cycle_cnt + 1;
                    if (compute_cycle_cnt >= COMPUTE_CYCLES - 1) begin
                        MSB_SA_Ready <= 1;
                        shift_add_done <= 1;
                        output_col_idx <= 0;
                        state <= S_OUTPUT;
                    end
                end
                S_OUTPUT: begin
                    dpe_done <= 1;  // held high during output phase
                    data_out <= 0;
                    for (b = 0; b < ELEMS_PER_STROBE; b = b + 1)
                        if (output_col_idx * ELEMS_PER_STROBE + b < NUM_COLS)
                            data_out[b*8 +: 8] <= vmm_result[output_col_idx * ELEMS_PER_STROBE + b][7:0];
                    if (output_col_idx < OUTPUT_CYCLES - 1) begin
                        output_col_idx <= output_col_idx + 1;
                    end else begin
                        state <= S_DRAIN;
                    end
                end
                S_DRAIN: begin
                    dpe_done <= 0;
                    reg_full <= 0;
                    load_count <= 0;
                    strobe_count <= 0;
                    output_col_idx <= 0;
                    MSB_SA_Ready <= 1;
                    shift_add_done <= 1;
                    state <= S_IDLE;
                end
                default: state <= S_IDLE;
            endcase
        end
    end

endmodule
